mapper.insert:
INSERT INTO follow_up_communication_session (
    register_id, department_id, status, ai_escalation_enabled
) VALUES (
    #{registerId}, #{departmentId}, COALESCE(#{status}, 'active'), COALESCE(#{aiEscalationEnabled}, 1)
)

mapper.update:
UPDATE follow_up_communication_session
SET doctor_last_active_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE follow_up_communication_session
SET ai_escalation_enabled = #{enabled}
WHERE id = #{id}

mapper.insert:
INSERT INTO follow_up_communication_message (
    session_id, sender_type, message_type, content, card_payload, summary_id, workflow_run_id
) VALUES (
    #{sessionId}, #{senderType}, COALESCE(#{messageType}, 'text'),
    #{content}, #{cardPayloadJson}::jsonb, #{summaryId}, #{workflowRunId}
)

INSERT INTO follow_up_case_summary (
    register_id, session_id, ai_draft_content, ai_medical_advice, ai_risk_alerts,
    doctor_content, status, shared_to_patient, workflow_run_id, model_id
) VALUES (
    #{registerId}, #{sessionId}, #{aiDraftContent}, #{aiMedicalAdvice}, #{aiRiskAlerts},
    #{doctorContent}, COALESCE(#{status}, 'draft'), COALESCE(#{sharedToPatient}, 0),
    #{workflowRunId}, #{modelId}
)

mapper.update:
UPDATE follow_up_case_summary
SET doctor_content = #{doctorContent}
WHERE id = #{id}

UPDATE follow_up_case_summary
SET status = 'revoked', shared_to_patient = 0
WHERE id = #{id}

mapper.select:
SELECT id AS "id"
FROM follow_up_daily_observation
WHERE register_id = #{registerId}
  AND observation_date = #{observationDate}
LIMIT 1
